I cannot directly generate a video file or a 3D animation that plays in your browser. However, I can provide you with the **complete code** to render a 3D house using **Three.js** (a popular JavaScript 3D library).

You can copy the code below, save it as an `.html` file (e.g., `house.html`), and open it in any modern web browser to see the 3D model.

### 3D House Viewer (HTML + JavaScript)

This code creates a scene with a ground plane, a house structure (walls, roof, door, and windows), and a camera that allows you to rotate around the model.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: Arial, sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">3D House Model<br>Left Click to Rotate | Right Click to Pan | Scroll to Zoom</div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        // 2. Camera Setup
        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 15, 20);

        // 3. Renderer Setup
        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        document.body.appendChild(renderer.domElement);

        // 4. Controls (Orbit)
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 5. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 6. Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xE0E0E0 }); // White walls
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown roof
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x4a3c31 }); // Dark wood
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.6 });
        const grassMaterial = new THREE.MeshStandardMaterial({ color: 0x4caf50 });

        // 7. Building the House
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeo = new THREE.BoxGeometry(10, 1, 8);
        const floor = new THREE.Mesh(floorGeo, wallMaterial);
        floor.position.y = 0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Walls
        const wallHeight = 4;
        const wallGeo = new THREE.BoxGeometry(10, wallHeight, 1);
        const wall1 = new THREE.Mesh(wallGeo, wallMaterial);
        wall1.position.set(0, wallHeight / 2 + 0.5, 4);
        wall1.castShadow = true;
        wall1.receiveShadow = true;
        houseGroup.add(wall1);

        const wall2 = new THREE.Mesh(wallGeo, wallMaterial);
        wall2.position.set(0, wallHeight / 2 + 0.5, -4);
        wall2.castShadow = true;
        wall2.receiveShadow = true;
        houseGroup.add(wall2);

        const wall3 = new THREE.Mesh(wallGeo, wallMaterial);
        wall3.position.set(4, wallHeight / 2 + 0.5, 0);
        wall3.castShadow = true;
        wall3.receiveShadow = true;
        houseGroup.add(wall3);

        const wall4 = new THREE.Mesh(wallGeo, wallMaterial);
        wall4.position.set(-4, wallHeight / 2 + 0.5, 0);
        wall4.castShadow = true;
        wall4.receiveShadow = true;
        houseGroup.add(wall4);

        // Roof
        const roofGeo = new THREE.ConeGeometry(9, 5, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = wallHeight + 2.5;
        roof.rotation.y = Math.PI / 4;
        roof.castShadow = true;
        houseGroup.add(roof);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 3, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMaterial);
        door.position.set(0, 1.5, 3.9);
        door.castShadow = true;
        houseGroup.add(door);

        // Windows (Simple squares)
        const windowGeo = new THREE.BoxGeometry(1.5, 1.5, 0.1);

        // Front Windows
        const win1 = new THREE.Mesh(windowGeo, windowMaterial);
        win1.position.set(-2.5, 3, 3.95);
        houseGroup.add(win1);

        const win2 = new THREE.Mesh(windowGeo, windowMaterial);
        win2.position.set(2.5, 3, 3.95);
        houseGroup.add(win2);

        // Side Windows
        const win3 = new THREE.Mesh(windowGeo, windowMaterial);
        win3.position.set(3.95, 3, -2.5);
        houseGroup.add(win3);

        const win4 = new THREE.Mesh(windowGeo, windowMaterial);
        win4.position.set(3.95, 3, 2.5);
        houseGroup.add(win4);

        scene.add(houseGroup);

        // 8. Ground (Grass)
        const groundGeo = new THREE.PlaneGeometry(100, 100);
        const ground = new THREE.Mesh(groundGeo, grassMaterial);
        ground.rotation.x = -Math.PI / 2;
        ground.position.y = 0;
        ground.receiveShadow = true;
        scene.add(ground);

        // 9. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  **Copy** the code block above.
2.  Create a new file on your computer named `house.html`.
3.  **Paste** the code into that file and save it.
4.  **Double-click** `house.html` to open it in Chrome, Firefox, Safari, or Edge.

### Features included:
*   **Geometry:** A simple house structure with walls, a cone-shaped roof, a door, and 4 windows.
*   **Lighting:** Ambient light for general visibility and a directional light (sun) that casts realistic shadows.
*   **Interactivity:** You can **click and drag** to rotate the camera, **right-click** to pan,
